#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00477Custom {
public:
    __aicore__ inline KernelCa6k00477Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t numSlices, uint32_t spatialSize,
                                float spatialSizeFloat, float eps)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        numSlices_ = numSlices;
        spatialSize_ = spatialSize;
        spatialSizeFloat_ = spatialSizeFloat;
        eps_ = eps;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(scratchQueue_, 2, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        for (uint32_t slice = blockIdx; slice < numSlices_; slice += blockNum) {
            uint32_t sliceOffset = slice * spatialSize_;

            // ----- first pass: compute sum and sum of squares -----
            float sum_x = 0.0f;
            float sum_x2 = 0.0f;
            uint32_t remaining = spatialSize_;
            uint32_t base = sliceOffset;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[base], curLen);

                // reduce sum for sum_x
                AscendC::LocalTensor<float> red1 = scratchQueue_.AllocTensor<float>();
                AscendC::ReduceSum(red1, xLocal, curLen);
                sum_x += red1(0);
                scratchQueue_.FreeTensor(red1);

                // reduce sum for sum_x2
                AscendC::LocalTensor<float> mul = scratchQueue_.AllocTensor<float>();
                AscendC::Mul(mul, xLocal, xLocal, curLen);
                AscendC::LocalTensor<float> red2 = scratchQueue_.AllocTensor<float>();
                AscendC::ReduceSum(red2, mul, curLen);
                sum_x2 += red2(0);
                scratchQueue_.FreeTensor(red2);
                scratchQueue_.FreeTensor(mul);

                inQueueX_.FreeTensor(xLocal);
                base += curLen;
                remaining -= curLen;
            }

            // compute mean and invStd
            float mean = sum_x / spatialSizeFloat_;
            float var = (sum_x2 / spatialSizeFloat_) - mean * mean;
            float invStd = 1.0f / (sqrt(var + eps_));

            // ----- second pass: normalize -----
            remaining = spatialSize_;
            base = sliceOffset;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[base], curLen);

                // y = (x - mean) * invStd
                AscendC::LocalTensor<float> tmp = scratchQueue_.AllocTensor<float>();
                AscendC::Adds(tmp, xLocal, -mean, curLen);
                AscendC::Muls(yLocal, tmp, invStd, curLen);
                scratchQueue_.FreeTensor(tmp);

                AscendC::DataCopy(yGm_[base], yLocal, curLen);
                outQueueY_.FreeTensor(yLocal);
                inQueueX_.FreeTensor(xLocal);
                base += curLen;
                remaining -= curLen;
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 2> scratchQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t numSlices_ {0};
    uint32_t spatialSize_ {0};
    float spatialSizeFloat_ {0.0f};
    float eps_ {1e-5f};
};

extern "C" __global__ __aicore__ void ca6k_00477_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00477Custom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.numSlices, tiling_data.spatialSize,
            tiling_data.spatialSizeFloat, tiling_data.eps);
    op.Process();
}
